function createSlidesFromBanners(banners) {
    return banners.map((banner)=>{
        const categoryName = banner.categoryId?.name || "Featured";
        const discount = banner.discount_percentage || 0;
        return {
            id: banner._id,
            title: banner.title,
            highlight: categoryName,
            description: `Special offers are available on the latest ${categoryName} collection.`,
            image: banner.image_url,
            badge: categoryName,
            offer: getOfferText(discount),
            product: banner.title,
            price: getOfferText(discount)
        };
    });
}
